{
  "answer": "f'(x) = 9x^2 + 4x - 5",
  "steps": [
    {
      "step": "d/dx(3x^3) = 9x^2",
      "explanation": "Power rule: d/dx(ax^n) = a*n*x^(n-1)",
      "proof": "Power Rule: d/dx(x^n) = n*x^(n-1) by first principles of differentiation"
    },
    {
      "step": "d/dx(2x^2) = 4x",
      "explanation": "Power rule with a=2, n=2",
      "proof": "Power Rule"
    },
    {
      "step": "d/dx(-5x) = -5",
      "explanation": "d/dx(ax) = a, since ax^1 -> a*1*x^0 = a",
      "proof": "Power Rule with n=1"
    },
    {
      "step": "d/dx(1) = 0",
      "explanation": "Derivative of a constant is 0",
      "proof": "Constant Rule: d/dx(c) = 0"
    }
  ],
  "proofs": [
    {
      "theorem": "Power Rule",
      "statement": "d/dx(x^n) = n*x^(n-1)",
      "applied_to": "each term"
    },
    {
      "theorem": "Sum Rule",
      "statement": "d/dx(f+g) = f' + g'",
      "applied_to": "all terms"
    },
    {
      "theorem": "Constant Rule",
      "statement": "d/dx(c) = 0",
      "applied_to": "constant term 1"
    }
  ],
  "method": "analytical"
}

{
  "answer": "6",
  "steps": [
    {
      "step": "\u222b(2x+3)dx = x^2 + 3x + C",
      "explanation": "Integrate term by term",
      "proof": "Power Rule for Integration: \u222bx^n dx = x^(n+1)/(n+1) + C"
    },
    {
      "step": "F(2) = 4 + 6 = 10",
      "explanation": "Evaluate antiderivative at upper bound",
      "proof": "FTC Part 2"
    },
    {
      "step": "F(0) = 0 + 0 = 0",
      "explanation": "Evaluate at lower bound",
      "proof": "FTC Part 2"
    },
    {
      "step": "10 - 0 = 6",
      "explanation": "Subtract",
      "proof": "FTC: \u222b_a^b f(x)dx = F(b) - F(a)"
    }
  ],
  "proofs": [
    {
      "theorem": "Fundamental Theorem of Calculus Part 2",
      "statement": "\u222b_a^b f(x)dx = F(b) - F(a) where F' = f",
      "applied_to": "definite integral"
    },
    {
      "theorem": "Power Rule for Integration",
      "statement": "\u222bx^n dx = x^(n+1)/(n+1) + C for n\u2260-1",
      "applied_to": "2x term"
    }
  ],
  "method": "analytical"
}

{
  "answer": "x = 2 or x = 3",
  "steps": [
    {
      "step": "Factor: (x-2)(x-3) = 0",
      "explanation": "Find two numbers that multiply to 6 and sum to -5: -2 and -3",
      "proof": "Vieta's formulas: for ax^2+bx+c, roots satisfy sum=-b/a, product=c/a"
    },
    {
      "step": "x - 2 = 0 \u2192 x = 2",
      "explanation": "Zero Product Property",
      "proof": "Zero Product Property: if ab=0 then a=0 or b=0"
    },
    {
      "step": "x - 3 = 0 \u2192 x = 3",
      "explanation": "Zero Product Property",
      "proof": "Zero Product Property"
    }
  ],
  "proofs": [
    {
      "theorem": "Zero Product Property",
      "statement": "If a*b = 0 then a=0 or b=0",
      "applied_to": "factored form"
    },
    {
      "theorem": "Vieta's Formulas",
      "statement": "For ax^2+bx+c=0, sum of roots = -b/a, product = c/a",
      "applied_to": "x^2-5x+6=0"
    }
  ],
  "method": "analytical"
}

{
  "answer": "2",
  "steps": [
    {
      "step": "Direct substitution gives 0/0 (indeterminate)",
      "explanation": "Substitute x=1: (1-1)/(1-1) = 0/0",
      "proof": "L'H\u00f4pital's Rule applies when limit is 0/0 or \u221e/\u221e"
    },
    {
      "step": "Factor numerator: x^2-1 = (x-1)(x+1)",
      "explanation": "Difference of squares",
      "proof": "Difference of Squares: a^2-b^2 = (a-b)(a+b)"
    },
    {
      "step": "Cancel (x-1): (x+1)",
      "explanation": "Since x\u22601, we can cancel",
      "proof": "Cancellation: f(x)/f(x) = 1 for f(x)\u22600"
    },
    {
      "step": "lim(x\u21921)(x+1) = 2",
      "explanation": "Direct substitution now works",
      "proof": "Continuity of polynomial"
    }
  ],
  "proofs": [
    {
      "theorem": "Difference of Squares",
      "statement": "a^2-b^2 = (a-b)(a+b)",
      "applied_to": "x^2-1"
    },
    {
      "theorem": "Direct Substitution Property",
      "statement": "If f is continuous at a, lim(x\u2192a)f(x) = f(a)",
      "applied_to": "x+1 at x=1"
    },
    {
      "theorem": "L'H\u00f4pital's Rule (alternative)",
      "statement": "If lim is 0/0, then lim f/g = lim f'/g'",
      "applied_to": "alternative method"
    }
  ],
  "method": "analytical"
}

{
  "answer": "The sum of two odd integers is always even",
  "steps": [
    {
      "step": "Let a = 2k+1, b = 2m+1 for integers k,m",
      "explanation": "Definition of odd: any odd integer can be written as 2k+1",
      "proof": "Definition of odd integers"
    },
    {
      "step": "a + b = 2k+1 + 2m+1 = 2(k+m) + 2 = 2(k+m+1)",
      "explanation": "Factor out 2",
      "proof": "Distributive property and algebraic manipulation"
    },
    {
      "step": "2(k+m+1) is even since (k+m+1) is an integer",
      "explanation": "Any number of form 2n where n is integer is even",
      "proof": "Definition of even: n is even iff n = 2j for some integer j"
    }
  ],
  "proofs": [
    {
      "theorem": "Definition of Odd",
      "statement": "n is odd iff n = 2k+1 for some integer k",
      "applied_to": "a and b"
    },
    {
      "theorem": "Definition of Even",
      "statement": "n is even iff n = 2j for some integer j",
      "applied_to": "a+b"
    },
    {
      "theorem": "Closure of Integers under Addition",
      "statement": "If k,m are integers, k+m+1 is an integer",
      "applied_to": "k+m+1"
    }
  ],
  "method": "analytical"
}

{
  "answer": "\u03bb = 1 and \u03bb = 3",
  "steps": [
    {
      "step": "det(A - \u03bbI) = det([[2-\u03bb,1],[1,2-\u03bb]]) = 0",
      "explanation": "Characteristic equation",
      "proof": "Eigenvalue definition: Av = \u03bbv, so det(A-\u03bbI)=0"
    },
    {
      "step": "(2-\u03bb)^2 - 1 = 0",
      "explanation": "Expand determinant of 2x2",
      "proof": "det([[a,b],[c,d]]) = ad-bc"
    },
    {
      "step": "\u03bb^2 - 4\u03bb + 3 = 0",
      "explanation": "Expand and simplify",
      "proof": "Algebraic expansion"
    },
    {
      "step": "(\u03bb-1)(\u03bb-3) = 0",
      "explanation": "Factor quadratic",
      "proof": "Factoring"
    },
    {
      "step": "\u03bb = 1 or \u03bb = 3",
      "explanation": "Zero Product Property",
      "proof": "Zero Product Property"
    }
  ],
  "proofs": [
    {
      "theorem": "Characteristic Equation",
      "statement": "det(A - \u03bbI) = 0 gives eigenvalues",
      "applied_to": "2x2 matrix"
    },
    {
      "theorem": "Determinant of 2x2",
      "statement": "det([[a,b],[c,d]]) = ad-bc",
      "applied_to": "characteristic matrix"
    }
  ],
  "method": "analytical"
}

{
  "answer": "1 + x + x^2/2 + x^3/6",
  "steps": [
    {
      "step": "f(0) = e^0 = 1",
      "explanation": "Zeroth derivative at 0",
      "proof": "Taylor: f(0) gives constant term"
    },
    {
      "step": "f'(0) = e^0 = 1",
      "explanation": "First derivative of e^x is e^x",
      "proof": "d/dx(e^x) = e^x"
    },
    {
      "step": "f''(0) = e^0 = 1",
      "explanation": "All derivatives of e^x are e^x",
      "proof": "d^n/dx^n(e^x) = e^x for all n"
    },
    {
      "step": "f'''(0) = e^0 = 1",
      "explanation": "Same",
      "proof": "Exponential derivative property"
    },
    {
      "step": "T_3(x) = 1 + x + x^2/2 + x^3/6",
      "explanation": "Taylor formula: \u03a3 f^(n)(0)/n! * x^n",
      "proof": "Taylor Series Theorem: f(x) \u2248 \u03a3 f^(n)(a)/n! (x-a)^n"
    }
  ],
  "proofs": [
    {
      "theorem": "Taylor Series",
      "statement": "f(x) = \u03a3 f^(n)(a)/n! (x-a)^n",
      "applied_to": "e^x at a=0"
    },
    {
      "theorem": "Derivative of Exponential",
      "statement": "d^n/dx^n(e^x) = e^x for all n\u22650",
      "applied_to": "all Taylor coefficients"
    }
  ],
  "method": "analytical"
}

{
  "answer": "25\u03c0",
  "steps": [
    {
      "step": "Circle: x^2 + y^2 = 25, so y = \u00b1\u221a(25-x^2)",
      "explanation": "Solve for y",
      "proof": "Pythagorean relation on circle"
    },
    {
      "step": "A = \u222b_{-5}^{5} 2\u221a(25-x^2) dx",
      "explanation": "Area = 2\u00d7 upper half (symmetry)",
      "proof": "Area under curve = integral; symmetry doubles upper half"
    },
    {
      "step": "Substitute x = 5sin(\u03b8), dx = 5cos(\u03b8)d\u03b8",
      "explanation": "Trigonometric substitution",
      "proof": "Standard trig substitution for \u221a(a^2-x^2)"
    },
    {
      "step": "A = 2\u222b_{-\u03c0/2}^{\u03c0/2} 25cos^2(\u03b8) d\u03b8 = 50\u222b cos^2(\u03b8)d\u03b8",
      "explanation": "Simplify",
      "proof": "Substitution and algebra"
    },
    {
      "step": "Using cos^2(\u03b8) = (1+cos(2\u03b8))/2",
      "explanation": "Half-angle identity",
      "proof": "Double angle formula: cos^2 = (1+cos2\u03b8)/2"
    },
    {
      "step": "A = 25[\u03b8 + sin(2\u03b8)/2]_{-\u03c0/2}^{\u03c0/2} = 25\u03c0",
      "explanation": "Evaluate",
      "proof": "Fundamental Theorem of Calculus"
    }
  ],
  "proofs": [
    {
      "theorem": "Trigonometric Substitution",
      "statement": "For \u221a(a^2-x^2), use x=a\u00b7sin(\u03b8)",
      "applied_to": "\u221a(25-x^2)"
    },
    {
      "theorem": "Half-Angle Identity",
      "statement": "cos^2(\u03b8) = (1+cos(2\u03b8))/2",
      "applied_to": "integrating cos^2"
    },
    {
      "theorem": "Fundamental Theorem of Calculus",
      "statement": "\u222b_a^b f(x)dx = F(b)-F(a)",
      "applied_to": "definite integral evaluation"
    }
  ],
  "method": "analytical"
}
